import{_ as l}from"./_plugin-vue_export-helper.cdc0426e.js";import{o as i,c as e,e as n}from"./app.f0561611.js";const a={},t=n('<h1 id="_9-b树" tabindex="-1"><a class="header-anchor" href="#_9-b树" aria-hidden="true">#</a> 9. B树</h1><h2 id="定义" tabindex="-1"><a class="header-anchor" href="#定义" aria-hidden="true">#</a> 定义</h2><p>B树是一种自平衡的多叉树，它的每个节点最多有m个子节点，m称为B树的阶。B树的特点是：</p><ul><li>每个节点最多有m个子节点，最少有m/2个子节点（根节点除外，根节点最少有1个子节点）。</li><li>除根节点外，每个非叶子节点至少有m/2个子节点。</li><li>所有叶子节点都在同一层。</li><li>每个节点中包含n个关键字，n个关键字对应n+1个子节点，关键字按从小到大的顺序排列，关键字和子节点的个数相同。</li><li>每个节点中的关键字：[k1, k2, k3, …, kn]，对应的子树为：[P1, P2, P3, …, Pn+1]，其中P1包含所有小于k1的关键字，P2包含所有大于等于k1且小于k2的关键字，…，Pn+1包含所有大于等于kn的关键字。</li><li>如果根节点不是叶子节点，则至少有两个子节点。</li><li>除根节点外，每个节点至少有m/2个关键字。</li><li>除根节点外，每个节点中的关键字个数n满足：m/2-1 &lt;= n &lt;= m-1。</li><li>除根节点外，如果某个节点中的关键字个数小于m/2-1，则需要从兄弟节点中借一个关键字，如果兄弟节点中的关键字个数大于m/2-1，则从兄弟节点中借一个关键字，否则需要合并兄弟节点。</li><li>如果根节点中的关键字个数为0，则将根节点的唯一子节点作为新的根节点。</li><li>B树的高度至多为logm(n+1)，n为关键字的个数。</li><li>B树的查找、插入、删除的时间复杂度为O(logm(n+1))。</li><li>B树的插入和删除操作可能会破坏B树的平衡性，因此需要进行调整。</li><li>B树的调整分为两种：分裂和合并。 <ul><li>分裂：当某个节点中的关键字个数大于m-1时，需要将该节点分裂成两个节点，将中间的关键字提升到父节点中。</li><li>合并：当某个节点中的关键字个数小于m/2-1时，需要将该节点与兄弟节点合并，将父节点中的关键字降下来。</li></ul></li></ul>',4),r=[t];function m(o,_){return i(),e("div",null,r)}const d=l(a,[["render",m],["__file","9. B树.html.vue"]]);export{d as default};
